var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_ON","text":{"KOREA":"카르멘! 네가 왜 앨리스 전대장의 얼굴을 하고 있는 건가!","JPN":"カルメン！　なぜ貴様がアリス戦隊長の格好をしているのだ！","ENG":"Carmen! Why do you have the face of Commander Alice?","TWN":"卡門！你為何偽裝成艾莉絲戰隊長的臉！"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_ON","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_EXPLOSION_FIRE_BIG_03"},{"id":"L4_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"웃……! 점잖지 못하게, 무차별로 쏟아붓긴……!","JPN":"うっ……！　大人げないわね。無差別に爆撃するなんて……！","ENG":"Ugh..! Such indecent, indiscriminate firing...!","TWN":"唔……！竟然這樣不管三七二十一地亂發射……！"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"후훗, 왜? 저쪽은 취향이 아니야?","JPN":"ふふっ、どうしたの？　あっちは趣味じゃない？","ENG":"Fuu fuu, what’s wrong? Isn’t that your type?","TWN":"呵呵，幹嘛？你不喜歡嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L8_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"당연하지! 손도 안 닿는 곳에서 괴롭히는걸!","JPN":"もちろんよ！　手も届かない距離で苛めるんだもの！","ENG":"Of course not! She’s bullying me from out of my reach!","TWN":"那還用說！竟然從那麼遠的地方發動攻擊！"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"류드밀라, 어떻게 여기까지 온 거야? 재조정이니 하지 않았어?","JPN":"リュドミラちゃん、どうやってここまで来たの？ 　再調整とか言ってなかった？","ENG":"Lyudmila, how did you get here? Didn’t you say you were readjusting?","TWN":"盧德米拉，你怎麼會來？不是在重整嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"음. 관리자님께 상황을 전달 받고 강력하게 중단을 요청드렸다.","JPN":"うむ。管理者殿から状況を聞き、断固中断することを要請した。","ENG":"Well. The Administrator informed me about the situation and I requested for the halt.","TWN":"嗯，我從管理者那裡收到消息後，便強烈要求暫停。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"잠깐, 뭐? 진통제도 안 듣는 주제에 또 고집 부렸어?","JPN":"ちょっと、何だって？　鎮痛剤も聞かないくせにまた意地を張ったの？","ENG":"What? Did you dig in your heels again? Your body doesn’t even respond to painkillers!","TWN":"你說什麼？鎮痛劑都還沒發揮效果，你就又恣意妄為嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"항상 최상의 상태로 전쟁을 수행할 수 있다는 보장은 없다. 전력은 늘 한정되어 있어.","JPN":"いつも最適の状態で戦争をこなせるという保証はない。戦力はいつも限られているんだ。","ENG":"There is no guarantee that one will always be able to do battle in the best possible condition. One’s power is always limited in some fashion.","TWN":"我的戰力有限，不保證能以最佳狀態上戰場。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"무엇보다 신뢰하는 전우들을 도와야 하는데 그것이 중요한가?","JPN":"なにより、信頼している戦友を助けなければならないのにそれが大事か？","ENG":"But above all, I must help my trusted comrades, is that not most important?","TWN":"不過重點是要幫助我信賴的戰友，其他不重要吧？"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"이 머릿속에 전술 교리만 들어찬 바보가 진짜……","JPN":"まったく、頭に戦術の教えばかり入っているバカが……","ENG":"Ugh, this idiot, with all this stereotypical war commander nonsense...","TWN":"你這個腦子只有戰術的傻瓜……"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"저게 어떤 녀석인지 그새 잊었어? 몇 명 온다고 끝날 일이 아니라고!","JPN":"あれが何なのかもう忘れたの？　何人来たところで済むことじゃないのよ！","ENG":"Have you forgotten what level of enemy this is? We aren’t going to be able to take care of this with just a few people arriving!","TWN":"你忘記對方是什麼樣的傢伙嗎？就算加上你們幾個事情也無法解決的！"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"지금 전력만으로는 버거운 상대임은 잘 알고 있다.","JPN":"今の戦力だけでは手ごわい相手であることは承知している。","ENG":"Even in our present state, I understand that she is a formidable opponent.","TWN":"我很清楚，光憑現在的戰力很可能不是她的對手。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"하지만…... 그렇다고 전우 곁을 떠나는 군인의 덕목을 나는 배운 적 없어, 알렉스.","JPN":"でも……だからといって戦友を置いて逃げるということを、私は習ったことがないんだ、アレックス。","ENG":"However... I have never learned to ever abandon my comrades, Alex.","TWN":"但是……難道因為這樣就要拋下戰友嗎？這不是我所學的軍人之道，雅蕾克絲。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"OPERATOR_NPC_NULL_A","text":{"KOREA":"마에스트로 네퀴티아. 콜드 케이스 137번과 대치 중입니다.","JPN":"マエストロ・ネキティア。コールドケース137番と対峙中です。","ENG":"Maestra Nequitia. Cold Case #137 is being confronted.","TWN":"指揮家 莉奎蒂亞，和Cold Case 137號對峙中。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L25_1","type":"dialog","speaker":"OPERATOR_NPC_NULL_A","text":{"KOREA":"아군의 공세가 계속 이어지고 있으나……! 피해를 입은 사실은 확인되지 않습니다!","JPN":"味方の攻勢が続いておりますが……！　ダメージを受けたのかは確認できません！","ENG":"Our attack continues...! But no damage is confirmed!","TWN":"雖然我方持續發動攻勢……！但沒有證據顯示有造成傷害！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"함포 개방. 구출팀은 즉시 강하해서 현장에 고립된 요원을 지원하세요.","JPN":"艦砲解放。救出班はただちに降下し、現場に孤立されたエージェントをサポートしなさい。","ENG":"Unlock the cannons. Rescue teams descend immediately and assist isolated personnel.","TWN":"開啟艦炮，立刻放下救援組，支援受困現場的人員。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"아가씨…… 구출팀을 보낸다고 하시더니 직접 오신 겁니까?","JPN":"お嬢様……救出班を送ると言われましたのに、直接お越しになられたのですか？","ENG":"Lady... You said you would send a rescue team, but you came in person?","TWN":"小姐……您說要派出救援組，難道您是親抵現場嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L28_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"이게 구출팀을 투입할 수 있는 가장 빠른 방법이랍니다. 효율적이죠.","JPN":"これが救出班を投入できる一番速い方法ですわ。効率的ですしね。","ENG":"It is the most efficient way to deploy a rescue team as fast as possible.","TWN":"聽說這是最快可以派出救援組的方法，滿有效的。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그러니 엄살 피우지 말고 어서 복귀해서 재정비하세요. 문제는 네퀴티아입니다.","JPN":"ですから弱音を吐かないで、早く復帰して再整備してください。問題はネキティアです。","ENG":"Stop being a crybaby, withdraw and reorganize. The problem is Nequitia.","TWN":"所以你就快回來重新整頓吧，現在的重點是莉奎蒂亞。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"저게 교본으로만 보던 정규 차원 함선……. 엄청 커…….","JPN":"あれが教本で見た正規次元艦船……大きすぎる……","ENG":"That must be the regular dimensional ship I've seen in textbooks... It’s massive...","TWN":"我以前只有在教科書上看過正規次元艦船……超巨大……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"손님들이……. 많이 왔네…… 팬케이크를 만들면 좋겠어…….","JPN":"お客さんが……いっぱい来たね……パンケーキを作った方がよさそう……","ENG":"So many guests... are here... I wish I could make some pancakes...","TWN":"有好多……客人……我來做點鬆餅吧……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"HORIZON_COLD_NULL_ON","text":{"KOREA":"흔적도 없이 증발하더니 이런 곳에 숨어 있었군요, 모르스.","JPN":"跡形もなく蒸発したと思ったらこんなところに潜んでいましたか、モールス。","ENG":"You disappeared without a trace and hid in a place like this, Mors.","TWN":"莫爾斯，我還以為你整個從人間蒸發，沒想到是躲在這種地方。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HORIZON_COLD_NULL_ON","text":{"KOREA":"교전 후 사라지지 마십시오. 당신에게 1차적으로 문의할 내용이 많습니다.","JPN":"交戦後、消えないでください。あなたには最初に問い合わせる事がたくさんあります。","ENG":"Do not disappear after this engagement. I have copious inquiries to ask you.","TWN":"交戰後請勿消失，我有很多問題要問你。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"이 전투가 끝난다면 기꺼이.","JPN":"この戦闘が終わったら喜んで。","ENG":"When this battle is over, gladly.","TWN":"等打完後我很樂意回答你。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"허나 시무르그의 후예여. 방심하지 말라. 상대는 힘이 아닌 기교로 세계를 유린하던 존재이니.","JPN":"しかし、シムルグの後裔よ。油断するな。相手は力ではなく技巧で世界を蹂躙した存在だ。","ENG":"But, Heir of Simurgh. Do not let your guard down. For this opponent ravaged the world with skill and guile, not strength.","TWN":"不過西摩格的後裔，千萬不能大意，對方可不是靠蠻力來毀壞世界，而是靠技巧。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"HORIZON_COLD_NULL_ON","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"HORIZON_COLD_NULL_ON","text":{"KOREA":"그렇군요. 5종이란 표현은 과장이라고 여겼습니다만, 인정해 드리죠.","JPN":"そうですね。第5種という表現は大げさだと思いましたが、認めてあげましょう。","ENG":"I see. I had thought the Category 5 designation was rather exaggerated, but I must concur.","TWN":"收到，原本還以為說5類是誇飾法，看來是認真的。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"HORIZON_COLD_NULL_ON","text":{"KOREA":"착실하게 기동 시간을 소모시키는 것으로 보아 계산이 빠르군요.","JPN":"起動時間をしっかり消耗させているところから見ると計算が速いですね。","ENG":"Looking at how you’re consuming activation time, you’re quick at math.","TWN":"看你可以準確地消耗啟動時間，你腦筋應該動得滿快的。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"HORIZON_COLD_NULL_ON","text":{"KOREA":"약아빠진 것도 무기라면 저 데몬 타입 침식체는 과적재 수준의 중무장입니다.","JPN":"ずる賢いことも武器であれば、あのデーモンタイプの侵食体は過積載レベルの重武装をしているわけです。","ENG":"If cleverness is a weapon, that Demon Type Corrupted Object is heavily armed to the teeth.","TWN":"狡猾也是種武器的話，你這個惡魔型侵蝕體應該是屬於超載的重武裝。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"칭찬으로 받아들이죠.","JPN":"誉め言葉として頂戴しましょう。","ENG":"I shall take that as a compliment.","TWN":"我接受你的讚美。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"허나 시무르그의 유해를 가로채간 입장에서 할 말은 아닌 것 같군요.","JPN":"しかし、シムルグの遺骸を盗んだ方に言われたくはありませんね。","ENG":"Though I think that’s not what you, the one who stole Simurgh’s remains, are supposed to say.","TWN":"不過竊取西摩格遺骸的你，應該沒資格說這種話吧？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"겉보기에는 거창해 보이는 전력입니다만……","JPN":"一見、大層な戦力に見えますが……","ENG":"A seemingly grandiose power, but...","TWN":"外表一副很厲害的樣子……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_COLD_NULL_ON","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"그래 봐야 결국 관리실패 이전과 비교하면 초라하기 짝이 없어요.","JPN":"結局、管理失敗以前と比べると貧弱極まりないですね。","ENG":"Compared to what it was before the Administration Failure, it is quite lacking.","TWN":"但和管理失敗前相比，簡直是太不堪。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_COLD_NULL_ON","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"그럼에도 이 세계가 아직 이렇게까지 연명하고 있다는 것은 필시 관리자님의 구상 덕분이겠죠.","JPN":"それでもこの世界がここまで延命しているということは、きっと管理者様の構想のおかげでしょう。","ENG":"Still. It is thanks to the Administrator’s plan that the world has survived this long.","TWN":"不過這個世界能夠苟延殘喘到如今，想必是拜管理者的計畫所賜吧？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"아쉽겠네. 여기서 한 번 더 죽으면 그 구상이 뭔지는 알 수 없을 테니까.","JPN":"残念ね。ここでもう一度死ねばその構想が何なのかわからなくなるから。","ENG":"That’s too bad. When you die again here, you won’t find out what the complete plan is.","TWN":"真可惜，你在這裡再死一次的話，就永遠無法得知那個計畫是什麼囉。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"기다리십시오, 부전대장님.","JPN":"お待ちください、副戦隊長。","ENG":"Wait. Deputy Commander.","TWN":"副戰隊長，別衝動！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"공격 한 번 막느라 만신창이가 되지 않으셨습니까.","JPN":"攻撃を防いでボロボロになってしまったではありませんか。","ENG":"Were you not thoroughly injured from blocking the single attack?","TWN":"你剛剛不過擋下她的攻擊一次，就弄得渾身是傷。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"팔에 입은 부상도 완치되지 않았습니다. 자칫하면 영영 못 쓰게 될지도 모릅니다.","JPN":"腕の怪我もまだ完治しておりません。間違ったら永遠に使えなくなるかもしれません。","ENG":"The injury to your arm has not healed completely. Any further injury and you might lose your arm forever.","TWN":"而且手臂上的傷也尚未痊癒，萬一有什麼差池，手臂很可能會廢掉。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"……상관없어. 저 자식에게 자기가 얼마나 위험한 물건을 버렸는지 가르쳐 줄 수만 있으면.","JPN":"……かまわないよ。あいつに自分がどれだけ危ないものを捨てたかを教えることができるならば。","ENG":"...I don’t care. As long as I can teach that scumbag just how dangerous the thing she threw away is.","TWN":"……無所謂，只要能教訓她，讓她知道她扔掉的東西有多危險！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"죽기가 두려워서 적들에게 의탁한 실패작이 말씀만은 당차시군요.","JPN":"死ぬのが怖くて敵に依託した失敗作の分際で、口だけは達者ですね。","ENG":"Sounds nervy and strong for a failed product who turned herself in to the enemy for being afraid to die.","TWN":"你這個因為怕死而投靠敵人的失敗品，嘴巴倒是很囂張呢。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"그러면 그 당찬 언변만큼의 실력도 보여 주시겠죠?","JPN":"それなら、それにふさわしい実力も見せていただけますね？","ENG":"Show me if you can truly practice what you preach.","TWN":"麻煩不要只出一張嘴，讓我見識一下你的實力吧？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"레아야…….","JPN":"レア……","ENG":"Leah...","TWN":"蕾亞……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"……음?","JPN":"……うむ？","ENG":"...Mm?","TWN":"……嗯？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"그, 그게…… 손님들께, 그러면 안 돼…….","JPN":"だ、だから……お客さんに、そんなことしてはダメ……","ENG":"D-Doing that... to the guests, you shouldn’t...","TWN":"怎麼可以……對客人這麼沒禮貌呢……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아, 아주머니! 이럴 때는 쥐 죽은 듯 가만히 있으세요, 좀!","JPN":"お、おばさん！　こういう時は静かにしてくださいよ、もう！","ENG":"Ah, Madam! Please be quiet at a time like this!","TWN":"伯母！我拜託你這時候就乖乖待在一邊，不要插嘴啦！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"하지만, 천사님이신걸…….","JPN":"でも、天使だもの……","ENG":"But she is the angel...","TWN":"可是她是天使……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"천사님……. 우리, 소중한 딸…….","JPN":"天使……私の、大切な娘……","ENG":"Angel... My, precious daughter...","TWN":"天使……我寶貝的女兒……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"손님들이 많으니까……. 팬케이크 재료를 사러 가면 좋겠다…….","JPN":"お客さんが多いから……パンケーキの材料を買いに行ったらいいね……","ENG":"There are so many guests... I should go buy ingredients for pancakes...","TWN":"客人這麼多……我去買鬆餅的材料……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"다 같이 먹으면……. 맛있을 거야…….","JPN":"みんなで食べると……おいしいよ……","ENG":"If we all ate together... It would be so nice...","TWN":"大家一起吃……一定很美味……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"저런…… 노망이 나서 상황 파악이 안 되나 봐.","JPN":"あらまあ……認知症で状況がわからないみたいね。","ENG":"Geez... Looks like she’s too senile to grasp the situation.","TWN":"真是的……那老太婆好像搞不清楚狀況。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"안 보이는 데로 치울까요, 지휘자님? 그러고 보니 이번에는 좀 더 젊은 인간을 기르고 싶은데.","JPN":"他所にしまっておきましょうか、マエストロ？ そういえば、今回はもっと若い人間を育てたいんですが。","ENG":"Do you want me to move her out of sight, Maestra Nequitia? I hope to raise someone younger this time...","TWN":"指揮家，要我把她處理掉嗎？下次我想養年輕一點的人類。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"맞다, 중사님이 있었지?","JPN":"そうだ、軍曹さんがいたわね？","ENG":"Ah right, what about the Sergeant?","TWN":"對吼，還有中士！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"히익……!","JPN":"ひいっ……！","ENG":"Eeep...!","TWN":"唔……！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"카르멘, 저는 아직 당신의 요청을 허락한 기억이 없답니다.","JPN":"カルメン、私はまだあなたの要請を許可した記憶はありませんよ。","ENG":"Carmen, I do not remember giving you my permission yet.","TWN":"卡門，我不記得我有答應過你的請求。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"우후후. 그렇지만 애완동물이라면요?","JPN":"うふふ。でもペットならどうですか？","ENG":"Fuu fuu. But what if we make her a pet?","TWN":"呵呵呵，那還是寵物呢？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L43_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"흠흠, 지휘자님? 마음에 안 들지만 여기서 철수하죠.","JPN":"ゴホン、マエストロ？　気に食わないけど、ここで引き下がりましょう。","ENG":"Uhh, Maestra Nequitia? I don’t like it, but I think we should get out of here.","TWN":"咳咳，指揮家，雖然我也不太願意，不過還是先撤退吧？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L44_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"침식파가 단절된 지역에 오래 머물수록, 저희가 불리한 건 사실이니까요.","JPN":"侵食波が途切れたところに長居すればするほど、私たちの分が悪いことは事実です。","ENG":"The longer we stay in areas where Corruption rays are cut off, the more at a disadvantage we are.","TWN":"畢竟在隔絕侵蝕波的地方待越久，對我們越不利。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L46_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"……악단의 향방을 판단하는 것은 월권이지만, 이번만큼은 묵인해 드리죠. 셰나.","JPN":"……楽団の方針を決めることは越権行為ですが、今回だけは見逃してさしあげますよ、シェナ。","ENG":"...It is not for you to direct the Ochestra, but I shall allow it this time. Shena.","TWN":"……決定樂團的去向是越矩的行為，但這次我就先不跟你計較，世娜。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_PRIDE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그럼요. 조금 과할 수 있지만 저만큼 지휘자님의 마음을 헤아리는 단원이 없잖아요?","JPN":"もちろんです。少しやりすぎるかもしれませんが、私ほどマエストロの気持ちを察している団員はいないでしょう。","ENG":"Of course. I might be overstepping myself, but no other member understands your heart more than me.","TWN":"我想也是，雖然我是有點超過，但有誰像我這麼懂指揮家的心呢？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"학회에서 저를 되살아나게 도왔으니, 응당 그에 걸맞은 요구가 기다리고 있을 겁니다.","JPN":"私の復活には学会の助力があったので、それ相応の要求が待っているはずです。","ENG":"The Society helped revive me, naturally they will want something in return.","TWN":"學會幫助我重生後，應該會提出相對的訴求。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"짐작가는 것이라면……. 심연에 계신 분 때문일까요.","JPN":"心当たりは……深淵にいらっしゃる方のことでしょうか。","ENG":"If I had to guess... It is probably because of that who is in the abyss.","TWN":"我猜……應該就是在深淵的那位吧？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"좋습니다, 셰나. 당신의 제안대로 하죠.","JPN":"いいでしょう、シェナ。あなたの提案どおりにしましょう。","ENG":"Alright, Shena. I shall do as you suggested.","TWN":"好，就照世娜你說的做吧。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"채택해 주셔서 감사합니다, 지휘자님.","JPN":"採用していただきありがとうございます、マエストロ。","ENG":"Thank you for accepting, Maestra Nequitia.","TWN":"指揮家英明～"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"크리스티나 브레히트 중사.","JPN":"クリスティーナ・ブレヒト軍曹。","ENG":"Sergeant Christina Brecht.","TWN":"克莉絲蒂娜·布萊希特中士。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"나…… 아, 아니, 저 말인가요?","JPN":"わ……い、いや、私ですか？","ENG":"Uhh... Um, you talking about little me?","TWN":"叫我幹嘛……不對，請問你是叫我嗎？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"네. 무공훈장의 수훈자인 당신 말입니다.","JPN":"はい。勲章の受勲者のあなたですよ。","ENG":"Yes. The war hero who received the Medal of Honor. I’m talking to you.","TWN":"對，就是你，授勳者。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"다시 만날 때까지, 그 늙은 인간을 잘 보살피세요.","JPN":"また会う日まで、その老人の世話をお願いします。","ENG":"Until we meet again, take care of the old woman.","TWN":"下次見面之前，請好好照顧那個老人。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"제게 남은 인간의 찌꺼기를 버린 뒤에, 생애 처음이자 마지막의 명연주를 경험하게 해 드리겠습니다.","JPN":"私に残っている人間の残滓を捨てた後、生涯最初で最後の名演奏をお聞かせいたします。","ENG":"I shall do away with the rest of the human scraps, and allow you to experience the first and last masterpiece of your life.","TWN":"在我扔掉僅存的人性後，會讓你體驗到絕無僅有的精采演奏。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"자, 자기 연주를 명연주라고 자평하는 건…… 자의식 과잉 아닌가요?","JPN":"じ、自分の演奏を名演奏と自己評価するのは……自意識過剰では？","ENG":"Uhh... Evaluating your own performance as a masterpiece... Isn’t that a bit much?","TWN":"這是老王賣瓜，自賣自誇嗎……你會不會自我感覺太良好？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"후훗…… 겁먹은 모습을 보이기 싫나 보군요.","JPN":"ふふっ……おびえた姿を見せたくないみたいですね。","ENG":"Fuu fuu. You wish to avoid appearing frightened.","TWN":"呵呵……是想用來嘲諷的話來掩飾你的恐懼嗎？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"좋습니다. 발전의 가능성이 엿보이네요. 최소한 상투적이지는 않았으니.","JPN":"いいでしょう。発展の可能性が見えます。少なくともありふれた表現ではありませんでしたし。","ENG":"Good. There is potential for development. At least you didn’t say something cliche.","TWN":"不錯，似乎滿有潛力的，至少不是老掉牙。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"그럼, 모쪼록 다음 공연에도 참석해 주시길.","JPN":"それでは、なにとぞ次の公演にもご参席ください。","ENG":"Then, please be sure to attend the next performance.","TWN":"那麼，下次的演出請你務必出席。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};